// src/store/slices/cartSlice.js
import { createSlice } from '@reduxjs/toolkit'; // 🔑 импорт createSlice

// 1️⃣ Получение состояния из LocalStorage
const getInitialState = () => {
  try {
    const persistedCart = localStorage.getItem('cartItems');
    return persistedCart ? JSON.parse(persistedCart) : [];
  } catch (error) {
    console.error("Error loading cart from storage:", error);
    return [];
  }
};

// 2️⃣ Сохранение состояния в LocalStorage
const saveState = (state) => {
  localStorage.setItem('cartItems', JSON.stringify(state));
};

const cartSlice = createSlice({
  name: 'cart',
  initialState: {
    items: getInitialState(),
  },
  reducers: {
    addToCart: (state, action) => {
      const { id, title, price, image, discont_price, quantity } = action.payload;
      const existingItem = state.items.find(item => item.id === id);
      const currentPrice = (discont_price !== null && discont_price !== undefined) ? discont_price : price;

      if (existingItem) {
        existingItem.count += quantity; // ✅ учитываем переданное количество
      } else {
        state.items.push({
          id,
          title,
          price: currentPrice,
          originalPrice: price,
          image,
          count: quantity, // ✅ начинаем с выбранного количества
        });
      }

      saveState(state.items);
    },

    increaseCount: (state, action) => {
      const { id } = action.payload;
      const item = state.items.find(item => item.id === id);
      if (item) item.count += 1;
      saveState(state.items);
    },

    decreaseCount: (state, action) => {
      const { id } = action.payload;
      const item = state.items.find(item => item.id === id);
      if (item && item.count > 1) item.count -= 1;
      saveState(state.items);
    },

    removeFromCart: (state, action) => {
      const { id } = action.payload;
      state.items = state.items.filter(item => item.id !== id);
      saveState(state.items);
    },

    clearCart: (state) => {
      state.items = [];
      saveState(state.items);
    }
  },
});

export const { addToCart, increaseCount, decreaseCount, removeFromCart, clearCart } = cartSlice.actions;
export default cartSlice.reducer;
